using System.Reflection;

var asm = Assembly.LoadFrom("/home/runner/.nuget/packages/mstest.testframework/4.1.0/lib/net8.0/MSTest.TestFramework.dll");
var assert = asm.GetType("Microsoft.VisualStudio.TestTools.UnitTesting.Assert")!;
var methods = assert.GetMethods(BindingFlags.Public | BindingFlags.Static)
    .Where(m => m.Name is "AreEqual" or "AreNotEqual" or "AreSame")
    .OrderBy(m => m.Name);
foreach (var m in methods)
{
    var parms = string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
    var generic = m.IsGenericMethod ? $"<{string.Join(",", m.GetGenericArguments().Select(a => a.Name))}>" : "";
    Console.WriteLine($"{m.Name}{generic}({parms})");
}
EOF
